import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {'12': {'1': "<p>In that day you will say: I praise you, YHWH; though you were angry with me, your anger has turned and you have comforted me. The doxology opens with the same formula as 2:11, 17, 20 — in that day — marking the transition from judgment (chapters 1-11) to restored worship. The anger-turned-to-comfort is the exact theological movement of the Servant's work: YHWH's wrath against sin is absorbed (53:5-6) so that comfort can reach the people (40:1). Paul quotes the spirit of this verse when he writes that we were under wrath but have been reconciled through the Son (Rom 5:10-11). The one who praises YHWH for anger-turned-to-comfort is the remnant saved through judgment — the community of the new creation.</p>", '2': "<p>God is my salvation! I will trust and will not be afraid; for YHWH, YHWH himself, is my strength and my song; he has become my salvation. This verse directly quotes the Song of Moses after the Red Sea crossing (Exod 15:2) and Ps 118:14 — all three contexts celebrate YHWH's salvific victory. The Isaianic reuse signals: the new exodus (chapters 40-55) has now arrived; its doxology repeats the first exodus doxology. The doubling of the divine name (YHWH YHWH) for emphasis is unique. In the NT, Jesus is the culmination of this salvation-pattern: the one in whom YHWH himself becomes salvation (Matt 1:21, his name is Jesus — YHWH saves). Zechariah's Benedictus (Luke 1:68-79) uses the same exodus-salvation vocabulary for the coming of the Messiah.</p>", '3': '<p>With joy you will draw water from the springs of salvation. The water-from-springs image echoes the wilderness water-from-rock (Exod 17:6, Num 20:8-11) and anticipates the rivers-of-living-water of Isa 41:17-18, 44:3. Jesus applies this image directly to himself at the Feast of Tabernacles: if anyone thirsts, let him come to me and drink; out of his heart will flow rivers of living water (John 7:37-38, citing Isa 55:1 and this verse). The springs of salvation are the inexhaustible gift of the Spirit that the Messiah provides — the water that becomes a spring welling up to eternal life (John 4:14).</p>', '4': "<p>Give thanks to YHWH; call on his name; make his deeds known among the nations; proclaim that his name is exalted. The praise breaks outward from the individual (v 1) to the community (v 3) to the nations (v 4) — the centrifugal movement of covenant blessing. Calling on the name of YHWH is the OT definition of true worship (Gen 4:26, 12:8); in the NT it becomes the specific act of confessing the Lordship of Jesus (Rom 10:9-13, Joel 2:32 / Acts 2:21). Making YHWH's deeds known among the nations is the Servant's commission (42:1, 49:6) and the church's mission (Matt 28:19-20).</p>", '5': "<p>Sing praises to YHWH, for he has done glorious things; make this known throughout all the earth! The glorious things (<em>gaavah</em>) that YHWH has done are the specific redemptive acts: exodus, Sinai, return from exile, and ultimately the Servant's atonement and resurrection. The universal proclamation — make this known throughout all the earth — is the scope of the Great Commission. The NT hymnody of Rev 15:3-4 (great and marvelous are your deeds, Lord God Almighty) echoes this verse as the song of the redeemed from every nation standing before the throne.</p>", '6': "<p>Cry aloud and shout for joy, you who dwell in Zion, for great is the Holy One of Israel in your midst! The doxology ends with the Isaianic title Holy One of Israel — the name introduced in 1:4 and central to the whole book's theology. YHWH's holiness is not a distant quality but in your midst — the Shekinah presence dwelling in the community (4:5-6). In the NT, the indwelling of the Holy Spirit makes every believer and the assembled church the dwelling of the Holy One: you are the temple of the Holy Spirit (1 Cor 6:19, 3:16). The shout of joy over the Holy One in the midst is Pentecostal worship — the reality John 7:39 and Acts 2 describe as the Spirit poured out on the community.</p>"}, '13': {'1': "<p>The oracle concerning Babylon opens the section of oracles against the nations (chapters 13-23). The superscription identifies this as prophetic vision (<em>hazon</em>). Babylon is theologically the arch-enemy of covenant community — the power that destroys Jerusalem, burns the temple, and exiles the people. In the NT, Babylon becomes the symbol of all anti-God empire (Rev 14:8, 17:5, 18:2) — Rome specifically, but also every coercive power that demands ultimate allegiance. The announcement of Babylon's fall is the foundation of the comfort of chapters 40-55 (40:2: her warfare is ended; 47:1-15: fall of Babylon in detail).</p>", '2': "<p>YHWH commands the marshaling of his army: raise a banner, wave a hand, that they may march through the gates of the rulers. The military imagery is of YHWH as divine warrior summoning his heavenly forces. The gates of the rulers — the enemy's strongholds — will be entered by YHWH's consecrated troops (v 3). In the NT, the binding of Satan (Rev 20:1-3) and the demolishing of strongholds (2 Cor 10:4-5) are the spiritual warfare equivalent of this verse: the same divine-warrior pattern applied to the powers of darkness.</p>", '3': "<p>I have given orders to my consecrated troops — those summoned to carry out YHWH's wrath. The consecrated (<em>mequddashim</em>) warriors are set apart for holy war. In the Christological reading, the Son of Man comes with his angels (Matt 25:31) as the ultimate consecrated warrior-company executing final judgment. The wrath of YHWH executed through human agents (Medes, v 17) is a type of the final judgment executed through the Son (John 5:27).</p>", '4': "<p>The roar of multitudes on the mountains — the massing of YHWH of hosts' army for battle. The cosmic scale of the army reflects the cosmic nature of the judgment: this is not merely political war but YHWH's universal sovereignty enforced. The NT equivalent is the armies of heaven following the rider on the white horse (Rev 19:14-15) — the same divine-warrior imagery applied to the return of Christ.</p>", '5': "<p>They come from a distant land, from the far end of the heavens — YHWH himself with the weapons of his wrath. The coming from the ends of heaven is theophanic language: when YHWH acts in judgment, the armies of heaven mobilize. The weapons of his wrath (<em>klei zaamo</em>) are both human agents (Medes) and cosmic forces. In Rev 6-16, the seals and bowls of wrath are YHWH's weapons deployed in the final judgment — the same pattern of divine wrath enacted through created agents.</p>", '6': "<p>Wail, for the day of YHWH is close at hand — it will come as devastation from the Almighty (<em>Shaddai</em>). The day of YHWH is the recurring prophetic announcement of YHWH's decisive intervention in history — both in immediate judgment (here, Babylon) and ultimately at the end of the age. Joel 2:1 uses this same formula, and Acts 2:20 applies it to the day before the great and glorious day of YHWH. In the NT, the day of the Lord is both the resurrection/judgment complex at Christ's return and any of its typological pre-enactments in history. Babylon's fall is a type of the ultimate fall of all anti-God empire.</p>", '7': "<p>At this every hand will go limp and every human heart will melt with fear. The universal terror response to YHWH's day recurs in Joel 2:6, Nah 2:10, Ezek 21:7 — it is the stereotyped response to the divine warrior's approach. In the NT, this motif transfers to the final judgment: every knee will bow (Phil 2:10-11) and every face will turn pale (Rev 6:16-17 — fall on us and hide us from the face of him who sits on the throne and from the wrath of the Lamb).</p>", '8': "<p>They will writhe like a woman in labor. The birth-pain image of the day of YHWH is picked up extensively in the NT as the birth-pangs of the new age: the beginning of birth pains (Matt 24:8), the creation groaning in labor pains (Rom 8:22). In the Christological framework, the day of YHWH's wrath that falls on Babylon is a type of the final judgment; the birth-pain image points to the new creation that emerges from judgment — the same pattern as the Servant's suffering (53:10-11) that produces offspring.</p>", '9': "<p>The day of YHWH is coming — relentless in wrath and burning anger — to turn the land into a ruin and wipe out every sinner from it. The sinners (<em>chataim</em>) are the target of the day's judgment. In the NT pattern, Jesus declares that he came not to condemn the world but to save it (John 3:17) — yet the rejection of the Son constitutes the judgment (John 3:18). The burning anger that judges the land of Babylon is the same holiness that, applied to the Servant, produces atonement (53:10 — it pleased YHWH to crush him).</p>", '10': "<p>The stars, sun, and moon will not give their light. The cosmic de-creation imagery — heavenly lights going dark — is the universal prophetic sign of YHWH's judgment day (Joel 2:10, 3:15; Ezek 32:7-8; Amos 8:9). Jesus quotes this verse directly in the Olivet Discourse (Matt 24:29: immediately after the distress of those days the sun will be darkened, the moon will not give its light). The cosmic signs are fulfilled both in historical judgments (each nation's collapse is a de-creation of its world) and ultimately at the parousia. The darkening of the sun at the crucifixion (Luke 23:44-45) is itself a miniature fulfillment — the judgment that fell on Christ at Golgotha was attended by the cosmic signs of the day of YHWH.</p>", '11': "<p>I will punish the world for its evil — put an end to the arrogance of the proud and humble the arrogance of tyrants. The universal moral judgment transcends Babylon: YHWH is judging the whole world's pride, not merely one empire. The NT equivalent is the judgment of the beast (Rev 19:20) and the great day of God Almighty (Rev 16:14): all human arrogance that sets itself against YHWH will be cut down. The arrogance of the proud is the sin of 14:13-14 (Babylon's king: I will make myself like the Most High) applied universally.</p>", '12': '<p>Human life will become rarer than pure gold — rarer than the gold of Ophir. The extreme scarcity of human life after the judgment describes the depopulation of Babylon. In the NT, the judgment of Babylon in Rev 18 results in the silence of merchants and seafarers who find no one to buy their goods — the economic and demographic collapse is total. The rarity of life after judgment is the dark context that makes the resurrection of the dead the supreme vindication of life: in the new creation, the loss of life in judgment is reversed.</p>', '13': "<p>I will make the heavens tremble, and the earth will be displaced from its foundations by YHWH's wrath. The cosmic shaking is the language of Sinai (Exod 19:18, Ps 68:8) applied to eschatological judgment. Heb 12:26-29 quotes this verse (I will shake not only the earth but also the heavens) to describe the removal of all that can be shaken so that only what cannot be shaken remains — the unshakeable kingdom received through the Son. The kingdom that Jesus brings is the one thing that survives the cosmic shaking of judgment.</p>", '14': "<p>Like a hunted gazelle or sheep scattered with no one to round them up, each will flee back to his own people. The scattering of Babylon's cosmopolitan population is the reversal of its imperial gathering of nations. The sheep-scattered image is used by Zechariah (13:7) and cited by Jesus: I will strike the shepherd and the sheep will be scattered (Matt 26:31) — the crucifixion as the moment of maximum scattering before the final regathering.</p>", '15': "<p>Anyone who is caught will be run through; anyone taken prisoner will fall by the blade. The total military defeat of Babylon leaves no survivors in the city. The sword of judgment is YHWH's agent — the same sword that ultimately falls on the Servant (53:8: he was cut off from the land of the living). The pattern: the sword of judgment must fall somewhere; it falls on the Servant instead of on the covenant community so that the covenant community can escape; those outside the Servant's covering (Babylon) face the sword directly.</p>", '16': "<p>Their children will be dashed to pieces; their homes looted, their wives violated. The extreme violence described here is both historically accurate for ancient warfare and theologically shocking. The prophetic tradition records it not as approval but as the full horror of the covenant curse enacted (Deut 28:32, 41). In the NT, the destruction of Jerusalem in 70 CE is described in similar terms (Luke 19:44: they will dash you to the ground, you and your children), making Babylon's judgment a type of the judgment on any city that rejects YHWH's messengers.</p>", '17': '<p>I am rousing the Medes against Babylon — a people who care nothing for silver and gold. The historical fulfillment came in 539 BCE when Cyrus the Mede/Persian conquered Babylon. YHWH names the specific human agent of his judgment over a century in advance, establishing his sovereignty over history. In the NT pattern, the Roman destruction of Jerusalem in 70 CE fulfills the same structure: YHWH uses a pagan empire as the instrument of covenant judgment. Ultimately, the one who wages war in righteousness (Rev 19:11) is the divine warrior himself, making explicit what was implicit in every historical judgment.</p>', '18': '<p>Their bows will cut the young men down; no mercy on infants, no pity on children. The comprehensiveness of the Median judgment against Babylon extends even to the most vulnerable — those whom ancient military practice sometimes spared for ransom. The mercilessness is presented as the character of the specific instrument YHWH has chosen, not as moral instruction. In the NT eschatological pattern, the final judgment shows no partiality (Rom 2:11, 1 Pet 1:17) — the same comprehensiveness applies to the judgment of all sin.</p>', '19': "<p>Babylon — the glory of kingdoms, the pride and beauty of the Chaldeans — will be like Sodom and Gomorrah when God overturned them. The Sodom comparison is the most severe in prophetic vocabulary: total, irreversible, exemplary destruction. Babylon's greatness makes its fall more spectacular: the higher the empire, the more visible the judgment. Jesus applies the same Sodom comparison to cities that reject his gospel (Matt 11:23-24): judgment will be more severe for Capernaum than for Sodom. The grandeur of Babylon is precisely the grandeur of all human self-construction that excludes YHWH — and its fall is the pattern of all such falls.</p>", '20': '<p>It will never be lived in or settled again; no Bedouin will pitch a tent there, no shepherds make their flocks lie down there. The permanent desolation of Babylon is the prophetic fulfillment that John picks up in Rev 18:21-23: the great city Babylon will be thrown down and will never be found again. The permanent-never-again formula signals eschatological irreversibility: this is not a cycle of rise and fall but a final end. The NT applies it to the ultimate fall of all godless civilization at the return of Christ.</p>', '21': '<p>Desert creatures, owls, ostriches, and wild goats will inhabit the ruins. The de-humanization of Babylon — the reversal of civilization into wilderness — is the anti-creation judgment: what was built up returns to chaos. In contrast, the new creation of chapters 65-66 and Rev 21-22 builds up what cannot be torn down. The howling creatures in the ruins of Babylon are the dark inverse of the singing trees and clapping mountains of Isa 55:12 — creation mourning the fall of what God condemned.</p>', '22': "<p>Hyenas will cry out in her citadels and jackals in her splendid palaces. Her time is about to come; her days will not be drawn out. The urgency — about to come, days not drawn out — creates the eschatological pressure of the whole oracle. The certainty of Babylon's fall is certain enough that it is already as good as happened: this is the prophetic perfect. In the NT, the same certainty marks the proclamations of Rev 14:8 (Fallen! Fallen is Babylon the Great!) — announced before the final judgment as if already accomplished because YHWH's word is certain.</p>"}, '14': {'1': "<p>YHWH will show compassion to Jacob and again choose Israel — the restoration follows immediately upon Babylon's judgment (ch 13). Compassion and choice are the two covenant terms that ground Israel's existence (Deut 7:6-7) and that the exile seemed to negate. The choosing-again is the key phrase: YHWH's election of Israel was not revoked by judgment, only suspended. The NT interprets Israel's hardening and future restoration in Rom 11:28-29 through exactly this structure: the gifts and calling of God are irrevocable; the same compassion that chose Israel will ultimately restore them.</p>", '2': "<p>Peoples will escort them home; Israel will possess foreigners as servants. The reversal of exile: those who were carried away in captivity will be escorted home by those who carried them. The former captors become servants — not in perpetual servitude but in the sense of the nations serving Israel's restoration (as Cyrus does in Isa 45). The NT applies the nations-serving-Israel pattern to the ingathering of the Gentiles into the people of God (Rom 15:27: if the Gentiles have come to share in their spiritual blessings...).</p>", '3': "<p>On the day YHWH gives rest from pain, suffering, and cruel servitude — the day of rest (<em>menuchah</em>) is the sabbath-rest of the people of God (Heb 4:9-11). The rest from servitude echoes the Exodus: YHWH remembered Israel's suffering in Egypt (Exod 3:7-8). The greater rest that remains for the people of God (Heb 4) is the Christological fulfillment: the Servant's yoke-taking (Matt 11:28-30: come to me, all who labor, and I will give you rest) is the eschatological sabbath-gift of which this verse speaks.</p>", '4': "<p>The taunt-song against the king of Babylon: How the tyrant has come to his end! The taunt-song (<em>mashal</em>) is the literary form of prophetic reversal — the powerful mocked in their fall by those they oppressed. In the NT, the fall of Rome/Babylon is lamented by merchants (Rev 18:9-19) but celebrated by heaven (Rev 18:20, 19:1-4). The contrast — earth mourning, heaven celebrating — is the eschatological division that the judgment of the beast reveals. The king of Babylon's fall is the type of the fall of the beast (Rev 19:20).</p>", '5': "<p>YHWH has shattered the rod of the wicked, the scepter of rulers. The rod (<em>matteh</em>) is the symbol of authority and power — the same rod that beat down peoples (v 6). YHWH's shattering of it is the assertion that his sovereignty supersedes all human power structures. In the Christological framework, the rod that beats down is answered by the rod of iron that the Messiah wields (Ps 2:9, Rev 2:27, 12:5, 19:15) — not the rod of oppression but the rod of righteous judgment that shatters the nations' self-constructed powers.</p>", '6': "<p>The rod that beat peoples in relentless blows, that kept nations under tyranny without relief. The sustained oppression of Babylon describes the condition of all who are under any coercive power. The without-relief — the refusal of rest — is the anti-sabbath character of tyranny: it works the people to exhaustion. Jesus names this as what he has come to reverse: come to me, all who are weary and burdened, and I will give you rest (Matt 11:28) — the rest that the tyrant's rod refused.</p>", '7': "<p>The whole earth rests quietly in peace; they burst into song. The peace that follows Babylon's fall is the sabbath-rest of all creation. The singing of creation when the tyrant falls echoes the cosmic singing of 55:12 — the mountains and hills break into song when the people go out in peace. In the NT, creation's liberation (Rom 8:21: creation itself will be liberated from its bondage to decay) is the eschatological fulfillment of this cosmic peace.</p>", '8': "<p>The cypress trees and cedars of Lebanon rejoice over Babylon's fall: since you have been brought low, no axeman has come against us. The trees personified as persecuted by the tyrant (who cut them for building projects) now celebrate freedom from exploitation. The personified creation's liberation is another anticipation of Rom 8:19-22: the creation waits with eager longing for the revealing of the sons of God. Creation's suffering under tyranny and creation's joy at tyrants' fall are both part of the cosmic drama of redemption.</p>", '9': "<p>Sheol stirs to meet the Babylonian king — the spirits of dead rulers rise to greet him. The underworld scene is one of the most vivid in the OT: all the kings he dethroned now taunt him from Sheol. The NT doctrine of Hades as the realm of the dead is built on texts like this one. The king of Babylon's descent to Sheol is the antitype of the Servant's descent: the Servant goes to the grave (53:9) but rises — he sees offspring and prolongs his days (53:10). The Babylonian king goes to Sheol and stays. The contrast is resurrection vs. permanent death.</p>", '10': "<p>You too have been brought to nothing — you are exactly like us. The once-mighty tyrant is leveled to the common condition of all the dead. In the NT, the equality of death — all die — is the context from which resurrection is the decisive break: death is swallowed up in victory (1 Cor 15:54-57). The resurrection of Jesus is precisely the moment when the king of kings is not leveled to the common condition of the dead but is raised as firstfruits (1 Cor 15:20) — the exact opposite of the Babylonian king's fate.</p>", '11': '<p>Your magnificence has been dragged to Sheol — your harp music, your bed of maggots. The luxurious pomp of empire (music, splendor) is replaced by its exact opposite (decay, maggots). The radical inversion — glory to corruption — is the pattern of fallen human pride. The NT reverses this for the Servant: what went into the grave in weakness is raised in power (1 Cor 15:43). The resurrection body is not subject to decay (Acts 2:27, citing Ps 16:10: you will not let your Holy One see decay).</p>', '12': "<p>How you have fallen from heaven, O Day Star, son of the Dawn! You have been hurled to the ground — you who laid nations prostrate! The Day Star (<em>helel ben shachar</em> — Lucifer in Latin) is the morning star / Venus, used as a symbol for the king of Babylon's pretension to divine status. This verse became the central OT text for the tradition of Satan's fall from heaven (Luke 10:18: I saw Satan fall like lightning from heaven; Rev 12:9: the great dragon was hurled down). The Babylonian king's pride is the human form of the angelic rebellion against YHWH — both are cast down from their presumed divine position.</p>", '13': "<p>For you said in your heart: I will climb to heaven; I will set my throne higher than the stars of God; I will sit on the mount of assembly in the far north. The five I will statements of Babylon's king are the grammar of the fall: five claims to divine prerogatives. The mount of assembly (<em>har moed</em>) is the cosmic mountain of the divine council. The NT background: Satan's temptation of Jesus in Matt 4:8-9 (all these kingdoms I will give you if you bow down to me) is the same bid for cosmic sovereignty — and Jesus' refusal is the reversal of Adam's and humanity's capitulation to the same temptation.</p>", '14': '<p>I will rise above the clouds; I will make myself like the Most High. The climax of the pretension: like the Most High (<em>Elyon</em>). The desire to be like God is the original sin (Gen 3:5 — you will be like God). The king of Babylon enacts in political form what Adam enacted in the garden. In contrast, Jesus — who being in the form of God did not count equality with God a thing to be grasped (Phil 2:6) — reverses the Edenic/Babylonian pattern: he did not grasp at divine status but emptied himself. The I will make myself like God is answered by the Word who was God and became flesh (John 1:1, 14).</p>', '15': '<p>But you are brought down to Sheol, to the depths of the pit. The reversal of the five I wills: you will be brought down. This is the judgment on all self-exaltation: everyone who exalts himself will be humbled (Luke 14:11, 18:14). The descent to the pit is the exact opposite of the ascension the king claimed. In the NT, this pattern reaches its culmination in the beast cast into the lake of fire (Rev 19:20) — the final fall of all who set themselves against the Most High.</p>', '16': "<p>Those who see him scrutinize: Is this the man who made the earth shake, who rattled kingdoms? The mockery at the fallen tyrant's insignificance in death shows that all imperial power is derivative and temporary — when YHWH removes it, nothing of the tyrant remains impressive. The NT applies this to the powers and principalities: the cross made a public spectacle of them (Col 2:15 — having disarmed the rulers and authorities, he put them to open shame by triumphing over them in the cross).</p>", '17': '<p>Who turned the world into a wasteland and demolished cities; who never released his prisoners to go home. The characterization of Babylon as a world-destroyer who keeps prisoners locked up is the profile of the power that Christ overcomes: he came to proclaim release to the captives (Isa 61:1 / Luke 4:18) — the exact reversal of the never-released-his-prisoners charge. The stronger man who binds the strong man and plunders his goods (Matt 12:29) is the messianic answer to this verse.</p>', '18': "<p>All the kings of nations lie in state, each in his own burial place. The proper burial of other kings — an honor given even to enemies — is contrasted with Babylon's shameful treatment (v 19-20). In the ancient world, proper burial was essential to dignity in death. The NT equivalent: Jesus — the innocent one condemned — is given a rich man's tomb (53:9, Matt 27:57-60), reversing the pattern; the king who falsely claimed divine status is denied even a proper grave.</p>", '19': "<p>But you are thrown out of your grave like a rejected branch (<em>netser nival</em>) — surrounded by slaughtered bodies. The rejected branch echoes and inverts the Branch of 4:2 (<em>tsemach YHWH</em>) and 11:1 (<em>netser</em> from Jesse's roots). The messianic Branch is the accepted, living shoot; the Babylonian king is the rejected, dead branch thrown out unburied. The contrast is total: both are called <em>netser</em> (shoot/branch) but with opposite outcomes — life vs. rejection, resurrection vs. unburied shame.</p>", '20': '<p>You will never be buried with them, because you destroyed your own country and murdered your own people. The ironic judgment: the one who killed his own people is denied the burial rites his murdered subjects received. The seed of evildoers will never be named again — generational extinction as the final form of the covenant curse. In contrast, the Servant who was cut off will see offspring and prolong his days (53:10) — the exact reversal of never be named again.</p>', '21': "<p>Prepare the execution ground for his sons — so they never rise to possess the land and fill the world with cities. The sons bear the fathers' guilt in the pattern of Deut 5:9 (visiting the iniquity of the fathers on the children to the third and fourth generation). In the NT, the judgment of generation on those who killed the prophets culminates in the judgment on Jerusalem in 70 CE (Matt 23:34-36: all this will come on this generation). The pattern: generational guilt accumulates until YHWH's patience ends and judgment falls completely.</p>", '22': "<p>I will rise up against Babylon — declares YHWH of hosts — and I will cut off its name and survivors, offspring and descendants. YHWH's personal rising against Babylon mirrors the Babylonian king's five I wills (vv 13-14) — but YHWH's I will actually stands while the tyrant's is cut off. In the NT, YHWH's rising to execute judgment is the Father's vindication of the Son: the one who was cut off (53:8) is raised, while the powers that cut him off are cut off in turn.</p>", '23': '<p>I will make it a haunt for the hedgehog and stagnant marshes; I will sweep it with the broom of annihilation. The broom of annihilation (<em>matate hashmad</em>) is the most complete image of purging: everything removed, nothing remaining. Rev 18:21 (a mighty angel picked up a boulder the size of a large millstone and threw it into the sea, saying: with such violence the great city Babylon will be thrown down) is the NT escalation of this image — catastrophic, irreversible, complete.</p>', '24': "<p>YHWH of hosts has sworn: Exactly as I have planned, so it will happen; exactly as I have purposed, so it will stand. The divine oath on the immutability of the divine plan grounds every subsequent oracle. Heb 6:17-18 applies this to the two immutable things (oath and promise) by which God confirmed his purposes — making it impossible for him to lie. The certainty of Babylon's fall is the same certainty as the certainty of Christ's triumph: YHWH's purpose is the foundation.</p>", '25': "<p>I will crush the Assyrian in my own land; I will trample him on my mountains. The oracle pivots from Babylon (vv 1-23) to Assyria — the immediate threat in Isaiah's time. YHWH's personal crushing in my own land signals that the holy land is YHWH's territory and cannot be permanently occupied by any foreign power. The yoke lifted from my people (v 25b) is the specific promise Jesus cites at Matt 11:28-30 — the yoke of Assyrian oppression is the type of the yoke of sin and death from which the Servant delivers his people.</p>", '26': "<p>This is the plan purposed for the whole earth, and this is the hand stretched out over all the nations. The plan (<em>haetsah</em>) of YHWH is singular and universal: one divine purpose governs all of world history. The stretched-out hand is the arm of YHWH that appears throughout Isaiah as the agent of salvation and judgment (51:5, 52:10, 53:1). In the NT, the same sovereign plan — pre-determined by God (Acts 2:23, 4:28: Jesus was handed over by God's deliberate plan) — governs even the cross: the apparent chaos of the passion is the outworking of the plan purposed for the whole earth.</p>", '27': "<p>YHWH of hosts has made this purpose, and who can overturn it? His hand is extended, and who can force it back? The rhetorical questions assert the absolute sovereignty of the divine will. Rom 8:31 applies the same logic: if God is for us, who can be against us? The irresistibility of YHWH's purpose is the ground of the believer's confidence — not in human strength but in the one whose outstretched hand no one can force back.</p>", '28': "<p>In the year King Ahaz died — the historical anchor for the Philistia oracle (vv 29-32). The dating to Ahaz's death links this oracle to the Immanuel-Emmanuel sign of chapters 7-8: Ahaz was the king who refused the sign, now his death marks a transition. The oracle that follows (vv 29-32) carries the messianic promise of 14:32 — the LORD has established Zion — into the context of the nations' question about Israel's fate.</p>", '29': "<p>Do not rejoice, O Philistia — because the rod that struck you is broken. For from the serpent's root a viper will come out, and its fruit will be a flying fiery serpent. The serpent's root is the Davidic line that will produce something more dangerous than the broken rod: the viper and flying fiery serpent are images of escalating threat. In the NT, the serpent/viper imagery is applied both to the enemies of God's people (Matt 3:7, 23:33: you brood of vipers!) and to the Serpent of Genesis whose head is crushed by the Seed of the woman (Gen 3:15, Rev 12:9). The flying fiery serpent becomes, in typological trajectory, the bronze serpent (Num 21:8-9) that Jesus applies to himself: just as Moses lifted up the serpent, so the Son of Man must be lifted up (John 3:14).</p>", '30': "<p>The poorest of the poor will have pasture and the needy will rest in safety. The poor and needy are the specific recipients of the messianic program: the Servant comes to bring good news to the poor (61:1 / Luke 4:18). Here, the fall of the threatening power (Philistia) is immediately connected to the flourishing of the poorest — YHWH's defense of the powerless is the positive side of his judgment on the powerful.</p>", '31': "<p>Wail, O gate! Cry out, O city! For a column of smoke rises from the north and there is no straggler in his ranks. The unstoppable army from the north — disciplined, with no stragglers — is YHWH's instrument against Philistia. The gates (places of civic life and commerce) wail because they will be the first breached. In the NT, the certainty of judgment on all who resist YHWH is the same: the gates of Hades will not prevail against the church (Matt 16:18) — but the gates of the world's cities are not guaranteed the same immunity.</p>", '32': "<p>What answer will be given to the envoys of the nations? The LORD has established Zion, and in her the poor of his people will take refuge. The closing verse is the theological heart: YHWH has established Zion — this is the answer to all geopolitical questions. Whatever the nations ask about Israel's fate, the answer is: Zion is YHWH's city and her poorest residents are under his protection. Jesus quotes this structure when he declares that the kingdom of heaven belongs to the poor in spirit (Matt 5:3) — the anawim of Zion are the first inheritors of the eschatological Zion. The established Zion of 14:32 is the new Jerusalem of Rev 21:2 — the city that comes down from heaven as the permanent dwelling of YHWH with his people.</p>"}, '15': {'1': "<p>The oracle concerning Moab: Ar and Kir, the two major cities, are destroyed in a single night. The speed — a single night — echoes the night of YHWH's judgments in Exodus (the angel of death at Passover) and the night fall of Babylon (Dan 5:30). Moab was Israel's neighbor and traditional enemy (Gen 19:37), yet also the homeland of Ruth — the Gentile ancestor of David. The ambiguity of Moab (enemy and ancestor of the messianic line) is part of the prophetic tension: even Moab's fall evokes sorrow (vv 5, 16:11).</p>", '2': "<p>The people of Moab go up to their temples and high places to weep, with shaved heads and cut-off beards — the bodily markers of extreme mourning in the ancient world. Their grief is religious: they seek their gods in the crisis. In the NT, the contrast is the mourning that leads to comfort: blessed are those who mourn, for they shall be comforted (Matt 5:4) — but this is mourning for sin before YHWH, not religious mourning directed toward false gods. Moab's mourning is directed to the wrong address.</p>", '3': "<p>In the streets they wear sackcloth; on rooftops and squares everyone mourns and weeps uncontrollably. The public, comprehensive grief of Moab is genuine — Isaiah does not mock it but records it with sympathy (v 5: my heart cries out for Moab). The prophetic empathy for the nation under judgment anticipates the NT posture of mourning with those who mourn (Rom 12:15). YHWH's judgment is real and severe; the grief it produces is also real. The compassion of the prophet for the judged nation is a small image of the divine compassion that will ultimately extend even to Moab (Ruth's lineage reaching David and the Messiah).</p>", '4': "<p>Heshbon and Elealeh raise their cry — even Moab's soldiers shudder. The sound of lamentation spreads geographically through Moab's territory: city after city is engulfed. The soldiers' shuddering signals total military collapse — the army that might defend Moab is as demoralized as the civilian population. In the Christological reading, this comprehensive grief-spreading is the dark image of what judgment day looks like when it arrives before the kingdom is secured through the Servant's work.</p>", '5': '<p>My heart cries out for Moab. The speaker — Isaiah, and perhaps YHWH through him — mourns for the enemy nation. The divine mourning over judgment is a consistent thread in prophetic literature (Jer 48:31-36 expands this lament for Moab; Ezek 33:11: I take no pleasure in the death of the wicked). Jesus expresses the same grief over Jerusalem: how often I wanted to gather your children together, but you were unwilling (Matt 23:37). The God who judges is the same God who mourns the necessity of judgment — both are expressions of his holiness and love.</p>', '6': "<p>The pools of Nimrim have dried up — grass withered, new growth gone, nothing green. The drying up of water sources is the ecological sign of YHWH's withdrawal of blessing (cf. Amos 4:7-8). The greening of a land depended on its water sources; the drying up of Nimrim signals that the land itself is dying along with the civilization. In the Christological framework, the rivers of living water that the Messiah provides (John 7:38, Isa 44:3) are the positive reversal of this ecological death — the Servant brings the waters of life where judgment has dried up every spring.</p>", '7': '<p>Whatever they have accumulated and saved they carry across the Brook of the Willows. The refugees of Moab flee with their accumulated wealth across the border brook — carrying what they can before it is taken from them. The brook becomes the liminal boundary between the old life (destroyed Moab) and the uncertain future. In the NT, the possessions-carried-into-exile motif contrasts with the treasure stored in heaven that moth and rust cannot destroy (Matt 6:19-20) — the wealth the refugee truly needs is the one that cannot be taken at the border.</p>', '8': "<p>The sound of weeping has encircled the whole border of Moab — the wailing reaches even Eglaim and Beer-elim. The lamentation is geographically comprehensive: no part of Moab escapes it. The encircling grief mirrors the encircling army — YHWH's judgment is as complete in its mourning as it is in its military form. In the NT, the weeping and gnashing of teeth (Matt 8:12, 22:13, 25:30) that marks the outer darkness is the eschatological form of this comprehensive mourning: those outside the kingdom will mourn the loss of what they could have had.</p>", '9': "<p>For the waters of Dimon run red with blood; and I will bring more upon Dimon — a lion against the fugitives of Moab and against what remains in the land. The blood in the waters echoes the first plague of Egypt (Exod 7:17-21) — YHWH's judgment on Egypt is now applied to Moab. The lion against the fugitives is the predator that hunts down those who flee the military disaster: there is no safe exit. In the broader Isaianic trajectory, the lion that destroys is answered by the lion and lamb lying down together (11:6, 65:25) — the messianic peace transforms the predator. The eschatological reversal of this lion-against-fugitives is the vision of universal safety in the new creation.</p>"}}

def main():
    data = load_comm('mkt-christ', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah christ: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-christ', 'isaiah', data)

if __name__ == '__main__':
    main()
